from sage.all_cmdline import *   # import sage library

_sage_const_1 = Integer(1); _sage_const_0 = Integer(0)
from sage.all import *
from Crypto.Util.number import long_to_bytes
import output  # hoặc bạn paste public_key, encrypted vào đây

A = list(map(ZZ, output.public_key))
T = ZZ(output.encrypted_flag)
n = len(A)

# 1. Tạo ma trận cơ sở
M = Matrix(ZZ, n+_sage_const_1 , n+_sage_const_1 )
for i in range(n):
    M[i, i] = _sage_const_1 
    M[i, n] = A[i]
M[n, n] = -T

# 2. Chạy LLL
R = M.LLL()

# 3. Tìm vector ngắn
for v in R:
    if v[-_sage_const_1 ] == _sage_const_0  and all(abs(x) <= _sage_const_1  for x in v[:-_sage_const_1 ]):
        bits = [int(x) for x in v[:-_sage_const_1 ]]
        break
else:
    # fallback: tìm vector gần 0
    v = min(R, key=lambda x: x.norm())
    bits = [_sage_const_1  if x < _sage_const_0  else _sage_const_0  for x in v[:-_sage_const_1 ]]

# 4. Chuyển bit về chuỗi bytes (LSB-first)
val = _sage_const_0 
for i, b in enumerate(bits):
    val |= (b << i)

flag = long_to_bytes(val)
print(flag)

